1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioResult {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
57	
58	const EPSILON = 1e-9;
59	
60	const roundUp = (n: number): number => Math.ceil(n - EPSILON);
61	
62	const MAIN_ITEM_BASE_PREMIUMS: Record<string, number> = {
63	  sword: 100,
64	  amulet: 60,
65	  staff: 80,
66	  potion: 40,
67	};
68	
69	const INSURANCE_VALUES: Record<string, number> = {
70	  sword: 1000,
71	  amulet: 600,
72	  staff: 800,
73	  potion: 400,
74	  rune: 250,
75	  moonstone: 250,
76	};
77	
78	const DEDUCTIBLE = 100;
79	const CAP_MULTIPLIER = 2;
80	
81	const insuranceValue = (type: string): number => INSURANCE_VALUES[type] ?? 0;
82	const policyCap = (items: Item[]): number =>
83	  CAP_MULTIPLIER * items.reduce((sum, item) => sum + insuranceValue(item.type), 0);
84	
85	const COMPONENT_BASE_PREMIUMS: Record<string, number> = {
86	  rune: 25,
87	  moonstone: 25,
88	};
89	
90	const ITEM_BASE_PREMIUMS: Record<string, number> = {
91	  ...MAIN_ITEM_BASE_PREMIUMS,
92	  ...COMPONENT_BASE_PREMIUMS,
93	};
94	
95	const COMPONENT_TYPES = new Set(Object.keys(COMPONENT_BASE_PREMIUMS));
96	const BLOCK_SIZE = 3;
97	const BLOCK_BASE = 60;
98	
99	const CURSE_SURCHARGE_RATE = 0.5;
100	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
101	const HIGH_ENCHANTMENT_THRESHOLD = 5;
102	const LOYALTY_DISCOUNT_RATE = 0.2;
103	const LOYALTY_THRESHOLD_YEARS = 2;
104	const FOLLOWUP_DISCOUNT_RATE = 0.15;
105	
106	const itemBase = (type: string): number => ITEM_BASE_PREMIUMS[type] ?? 0;
107	
108	const componentGroupBase = (count: number, unitBase: number): number => {
109	  if (count === BLOCK_SIZE) return BLOCK_BASE;
110	  return count * unitBase;
111	};
112	
113	const itemSurchargeRate = (item: Item): number => {
114	  let rate = 0;
115	  if (item.cursed) rate += CURSE_SURCHARGE_RATE;
116	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
117	    rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
118	  }
119	  return rate;
120	};
121	
122	const itemSurcharge = (item: Item, base: number): number =>
123	  base * itemSurchargeRate(item);
124	
125	const policyModifierRate = (customer: Customer, priorQuoteCount: number): number => {
126	  let rate = FIRST_INSURANCE_SURCHARGE_RATE;
127	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
128	    rate -= LOYALTY_DISCOUNT_RATE;
129	  }
130	  if (priorQuoteCount >= 1) {
131	    rate -= FOLLOWUP_DISCOUNT_RATE;
132	  }
133	  return rate;
134	};
135	
136	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
137	
138	const componentsBaseTotal = (components: Item[]): number => {
139	  const counts = new Map<string, number>();
140	  for (const item of components) {
141	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
142	  }
143	  let total = 0;
144	  for (const [type, count] of counts) {
145	    total += componentGroupBase(count, itemBase(type));
146	  }
147	  return total;
148	};
149	
150	const mainItemsBaseTotal = (mainItems: Item[]): number =>
151	  mainItems.reduce((sum, item) => sum + itemBase(item.type), 0);
152	
153	const mainItemsSurchargeTotal = (mainItems: Item[]): number =>
154	  mainItems.reduce((sum, item) => sum + itemSurcharge(item, itemBase(item.type)), 0);
155	
156	const quotePremium = (items: Item[], customer: Customer, priorQuoteCount: number): number => {
157	  const mainItems = items.filter((item) => !isComponent(item));
158	  const components = items.filter(isComponent);
159	
160	  const policyBase = mainItemsBaseTotal(mainItems) + componentsBaseTotal(components);
161	  const itemSurchargeTotal = mainItemsSurchargeTotal(mainItems);
162	  const policyModifierTotal = policyBase * policyModifierRate(customer, priorQuoteCount);
163	
164	  const total = policyBase + itemSurchargeTotal + policyModifierTotal;
165	  return roundUp(total) + PROCESSING_FEE;
166	};
167	
168	const damagePayout = (damage: Damage): number =>
169	  Math.max(0, damage.amount - DEDUCTIBLE);
170	
171	const processClaim = (step: ClaimStep, scenario: Scenario): ClaimResult => {
172	  const policyStep = scenario.steps[step.policy] as QuoteStep;
173	  const cap = policyCap(policyStep.items);
174	  const payout = step.incident.damages.reduce(
175	    (sum, damage) => sum + damagePayout(damage),
176	    0,
177	  );
178	  return { payout, remainingCap: cap - payout };
179	};
180	
181	const processStep = (
182	  step: Step,
183	  scenario: Scenario,
184	  priorQuoteCount: number,
185	): StepResult => {
186	  if (step.op === "quote") {
187	    return { premium: quotePremium(step.items, scenario.customer, priorQuoteCount) };
188	  }
189	  return processClaim(step, scenario);
190	};
191	
192	export const processScenario = (scenario: Scenario): ScenarioResult => {
193	  let priorQuoteCount = 0;
194	  const results: StepResult[] = scenario.steps.map((step) => {
195	    const result = processStep(step, scenario, priorQuoteCount);
196	    if (step.op === "quote") priorQuoteCount++;
197	    return result;
198	  });
199	  return { results };
200	};
