const damagePayout = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE);

const totalPayout = (damages: Damage[]): number =>
  damages.reduce((sum, damage) => sum + damagePayout(damage), 0);

const policyItems = (scenario: Scenario, policyIndex: number): Item[] =>
  (scenario.steps[policyIndex] as QuoteStep).items;

const processClaim = (step: ClaimStep, scenario: Scenario): ClaimResult => {
  const cap = policyCap(policyItems(scenario, step.policy));
  const payout = totalPayout(step.incident.damages);
  return { payout, remainingCap: cap - payout };
};
